module top_module(in1,
            in2,
            sum_result,
            clk,
            rst);input [3:0]in1,in2;
    input rst,clk;

    output reg [4:0] sum_result;

    always@(posedge clk or posedge rst)
    begin
        if(rst==1)
        begin
            sum_result<=0;
        end
        else 
        begin
            sum_result<=in1+in2;    
        end
    end

endmodule
